using System.Text.Json.Serialization;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace OutwardVoyager;

/// <summary>
/// Reads live game state via IL2CPP interop assemblies generated by BepInEx on first launch.
/// Entry point: SplitScreenManager.Instance.GetLocalPlayer(0).ControlledCharacter
/// </summary>
public class GameStateReader
{
    public GameState ReadCurrentState()
    {
        var playerState = GetPlayerState();
        var playerPos = new Vector3(playerState.PositionX, playerState.PositionY, playerState.PositionZ);

        return new GameState
        {
            SceneName = GetCurrentScene(),
            Player = playerState,
            NearbyDead = GetNearbyDead(playerPos),
            NearbyInteractions = GetNearbyInteractions(playerPos),
            Inventory = GetInventory(),
            ScreenMessage = GetScreenMessage(),
            Timestamp = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds(),
        };
    }

    private static string GetCurrentScene()
    {
        try
        {
            return SceneManager.GetActiveScene().name ?? "unknown";
        }
        catch
        {
            return "unknown";
        }
    }

    private static PlayerState GetPlayerState()
    {
        try
        {
            var charMgr = CharacterManager.Instance;
            if (charMgr == null) return new PlayerState();

            var character = charMgr.GetFirstLocalCharacter();
            if (character == null) return new PlayerState();

            var pos = character.transform.position;
            var rot = character.transform.eulerAngles;
            var stats = character.Stats;

            // Camera rotation for camera-relative movement
            float cameraRotY = 0f;
            var cam = Camera.main;
            if (cam != null)
                cameraRotY = cam.transform.eulerAngles.y;

            float health = 0, maxHealth = 0, stamina = 0, maxStamina = 0, mana = 0, maxMana = 0;
            float food = 0, maxFood = 100, drink = 0, maxDrink = 100, sleep = 0, maxSleep = 100;
            float bodyTemp = 20f;

            if (stats != null)
            {
                health    = stats.CurrentHealth;
                maxHealth = stats.MaxHealth;
                stamina   = stats.CurrentStamina;
                maxStamina= stats.MaxStamina;
                mana      = stats.CurrentMana;
                maxMana   = stats.MaxMana;

                // Dump all field names on first read so we can see what's available
                DumpStatFieldsOnce(stats);

                // Survival needs — Outward stores these as Stat objects
                // "water" is the internal name for drink needs in Outward
                TryReadStat(stats, new[]{"m_foodNeeds","FoodNeeds","m_food","Food","m_hunger","Hunger"}, ref food, ref maxFood);
                TryReadStat(stats, new[]{"m_waterNeeds","WaterNeeds","m_drinkNeeds","DrinkNeeds","m_water","Water","m_drink","Drink","m_thirst","Thirst"}, ref drink, ref maxDrink);
                TryReadStat(stats, new[]{"m_sleepNeeds","SleepNeeds","m_sleep","Sleep","m_fatigue","Fatigue"}, ref sleep, ref maxSleep);
                bodyTemp = TryReadFloat(stats, new[]{"BodyTemperature","m_bodyTemperature","Temperature","m_temperature"});
            }

            // Active status effects (burning, bleeding, poisoned, etc.)
            var statusEffects = new List<string>();
            try
            {
                var mgr = character.StatusEffectMngr;
                if (mgr?.Statuses != null)
                {
                    foreach (var effect in mgr.Statuses)
                    {
                        if (effect == null) continue;
                        string name = effect.IdentifierName ?? effect.name ?? "";
                        if (!string.IsNullOrWhiteSpace(name))
                            statusEffects.Add(name);
                    }
                }
            }
            catch { /* status effect read failed — skip */ }

            return new PlayerState
            {
                Health      = health,    MaxHealth   = maxHealth,
                Stamina     = stamina,   MaxStamina  = maxStamina,
                Mana        = mana,      MaxMana     = maxMana,
                Food        = food,      MaxFood     = maxFood,
                Drink       = drink,     MaxDrink    = maxDrink,
                Sleep       = sleep,     MaxSleep    = maxSleep,
                BodyTemperature = bodyTemp,
                StatusEffects = statusEffects,
                PositionX = pos.x, PositionY = pos.y, PositionZ = pos.z,
                RotationY = rot.y,
                CameraRotationY = cameraRotY,
                IsDead = character.IsDead,
                IsInCombat = character.InCombat,
            };
        }
        catch (Exception ex)
        {
            Plugin.Log.LogWarning($"GameStateReader error: {ex.Message}");
            return new PlayerState();
        }
    }

    // ── Survival stat helpers ────────────────────────────────────────────────

    /// <summary>
    /// Try to read a Stat object (CurrentValue/MaxValue) from CharacterStats by field name.
    /// Outward's Stat class wraps survival needs; tries multiple possible names.
    /// </summary>
    // One-time field dump — logs all CharacterStats field names so we can find survival stat fields
    private static bool _statFieldsDumped = false;
    private static void DumpStatFieldsOnce(CharacterStats stats)
    {
        if (_statFieldsDumped) return;
        _statFieldsDumped = true;
        try
        {
            var statsType = stats.GetIl2CppType();
            var fields = statsType.GetFields(
                Il2CppSystem.Reflection.BindingFlags.NonPublic |
                Il2CppSystem.Reflection.BindingFlags.Public |
                Il2CppSystem.Reflection.BindingFlags.Instance);
            Plugin.Log.LogInfo($"[StatsDump] CharacterStats has {fields.Count} fields:");
            foreach (var f in fields)
                Plugin.Log.LogInfo($"  Field: {f.FieldType?.Name ?? "?"} {f.Name}");
        }
        catch (Exception ex) { Plugin.Log.LogWarning($"[StatsDump] failed: {ex.Message}"); }
    }

    private static void TryReadStat(CharacterStats stats, string[] names,
        ref float current, ref float max)
    {
        try
        {
            var statsType = stats.GetIl2CppType();
            foreach (var name in names)
            {
                var field = statsType.GetField(name,
                    Il2CppSystem.Reflection.BindingFlags.NonPublic |
                    Il2CppSystem.Reflection.BindingFlags.Public |
                    Il2CppSystem.Reflection.BindingFlags.Instance);
                if (field == null) continue;

                var val = field.GetValue(stats);
                if (val == null) continue;

                var statType = val.GetIl2CppType();
                // Try both CamelCase and m_camelCase property names
                foreach (var curName in new[] { "CurrentValue", "m_currentValue", "Value", "m_value" })
                {
                    var curProp = statType.GetProperty(curName,
                        Il2CppSystem.Reflection.BindingFlags.Public |
                        Il2CppSystem.Reflection.BindingFlags.NonPublic |
                        Il2CppSystem.Reflection.BindingFlags.Instance);
                    if (curProp != null)
                    {
                        var r = curProp.GetValue(val, null);
                        if (r != null) { current = Il2CppUnbox<float>(r); break; }
                    }
                }
                foreach (var maxName in new[] { "MaxValue", "m_maxValue", "Max", "m_max" })
                {
                    var maxProp = statType.GetProperty(maxName,
                        Il2CppSystem.Reflection.BindingFlags.Public |
                        Il2CppSystem.Reflection.BindingFlags.NonPublic |
                        Il2CppSystem.Reflection.BindingFlags.Instance);
                    if (maxProp != null)
                    {
                        var r = maxProp.GetValue(val, null);
                        if (r != null) { max = Il2CppUnbox<float>(r); break; }
                    }
                }
                Plugin.Log.LogInfo($"[Stat] {name} → current={current} max={max}");
                return;
            }
        }
        catch { /* field not found in this version — leave defaults */ }
    }

    /// <summary>Try to read a plain float field from CharacterStats by multiple possible names.</summary>
    private static float TryReadFloat(CharacterStats stats, string[] names)
    {
        try
        {
            var statsType = stats.GetIl2CppType();
            foreach (var name in names)
            {
                var prop = statsType.GetProperty(name,
                    Il2CppSystem.Reflection.BindingFlags.Public |
                    Il2CppSystem.Reflection.BindingFlags.Instance);
                if (prop != null)
                {
                    var val = prop.GetValue(stats, null);
                    if (val != null) return Il2CppUnbox<float>(val);
                }
                var field = statsType.GetField(name,
                    Il2CppSystem.Reflection.BindingFlags.NonPublic |
                    Il2CppSystem.Reflection.BindingFlags.Public |
                    Il2CppSystem.Reflection.BindingFlags.Instance);
                if (field != null)
                {
                    var val = field.GetValue(stats);
                    if (val != null) return Il2CppUnbox<float>(val);
                }
            }
        }
        catch { }
        return 20f; // default comfortable temperature
    }

    private const float ScanRadius = 100f;

    // Keywords that suggest a visible object is a corpse/body.
    private static readonly string[] CorpseKeywords =
        ["corpse", "dead", "body", "cadaver", "skeleton", "skull", "bones", "remains"];

    private static List<NearbyDeadEntry> GetNearbyDead(Vector3 playerPos)
    {
        var result   = new List<NearbyDeadEntry>();
        var seenIds  = new HashSet<int>();

        var playerChar = CharacterManager.Instance?.GetFirstLocalCharacter();
        int playerInstanceId = playerChar != null ? playerChar.gameObject.GetInstanceID() : -1;

        try
        {
            // ── Pass 1: Collider-based scan (Characters with IsDead, items) ─────
            var colliders = Physics.OverlapSphere(playerPos, ScanRadius);
            foreach (var col in colliders)
            {
                if (col == null) continue;
                var root = col.transform.root.gameObject;
                int id   = root.GetInstanceID();
                if (!seenIds.Add(id)) continue;
                if (id == playerInstanceId) continue;

                var pos  = root.transform.position;
                float dist = FlatDistance(pos, playerPos);

                var ch = root.GetComponentInChildren<Character>();
                if (ch != null)
                {
                    if (!ch.IsDead) continue;
                    result.Add(MakeEntry(ch.UID?.ToString() ?? id.ToString(),
                        ch.name, "character", pos, dist));
                    continue;
                }

                if (MatchesCorpseKeyword(root.name))
                    result.Add(MakeEntry(id.ToString(), root.name, "prop", pos, dist));
            }

            // NOTE: Pass 2 (FindObjectsOfType<Renderer>) was removed — it likely
            // caused game crashes in IL2CPP. Use the "scan_nearby" command instead
            // for thorough on-demand detection via scene hierarchy walk.
        }
        catch (Exception ex)
        {
            Plugin.Log.LogWarning($"NearbyDead scan error: {ex.Message}");
        }

        result.Sort((a, b) => a.Distance.CompareTo(b.Distance));

        return result;
    }

    private static bool MatchesCorpseKeyword(string name)
    {
        string lower = name.ToLowerInvariant();
        return Array.Exists(CorpseKeywords, k => lower.Contains(k));
    }

    private static float FlatDistance(Vector3 a, Vector3 b)
    {
        var d = a - b;
        d.y = 0f;
        return d.magnitude;
    }

    private static NearbyDeadEntry MakeEntry(string uid, string name, string source,
        Vector3 pos, float dist) => new()
    {
        Uid = uid, Name = name, Source = source,
        X = pos.x, Y = pos.y, Z = pos.z, Distance = dist,
    };

    // ── Nearby interactions ─────────────────────────────────────────────────

    private const float InteractionRadius = 6f;

    private static List<NearbyInteractionEntry> GetNearbyInteractions(Vector3 playerPos)
    {
        var result = new List<NearbyInteractionEntry>();
        try
        {
            var colliders = Physics.OverlapSphere(playerPos, InteractionRadius);
            var seen = new HashSet<int>();

            foreach (var col in colliders)
            {
                if (col == null) continue;
                var root = col.transform.root.gameObject;
                int id = root.GetInstanceID();
                if (!seen.Add(id)) continue;

                // Look for InteractionActivator on the root or any child
                var activator = root.GetComponentInChildren<InteractionActivator>();
                if (activator == null) continue;
                if (!activator.gameObject.activeInHierarchy) continue;

                // Use the activator/collider position — NOT the root position which can be
                // hundreds of metres away if the root is a zone manager.
                var pos = activator.transform.position;
                float dist = FlatDistance(pos, playerPos);

                // Attempt to read a label — try known field/property names via reflection
                string label = TryGetInteractionLabel(activator) ?? root.name;

                result.Add(new NearbyInteractionEntry
                {
                    Uid  = root.name,
                    Label = label,
                    Distance = (float)Math.Round(dist, 1),
                    X = pos.x, Y = pos.y, Z = pos.z,
                });
            }
        }
        catch (Exception ex)
        {
            Plugin.Log.LogWarning($"NearbyInteractions scan error: {ex.Message}");
        }

        result.Sort((a, b) => a.Distance.CompareTo(b.Distance));
        return result;
    }

    private static string? TryGetInteractionLabel(Il2CppSystem.Object obj)
    {
        try
        {
            var type = obj.GetIl2CppType();
            // Try common label property/field names in Outward's InteractionActivator
            foreach (var propName in new[] { "InteractionTitle", "m_interactionTitle", "Title", "Label", "m_label" })
            {
                var prop = type.GetProperty(propName,
                    Il2CppSystem.Reflection.BindingFlags.Public |
                    Il2CppSystem.Reflection.BindingFlags.NonPublic |
                    Il2CppSystem.Reflection.BindingFlags.Instance);
                if (prop != null)
                {
                    var val = prop.GetValue(obj, null);
                    if (val != null)
                    {
                        string s = val.ToString() ?? "";
                        if (!string.IsNullOrWhiteSpace(s)) return s;
                    }
                }
            }
        }
        catch { /* reflection failed — fall back to name */ }
        return null;
    }

    // ── Inventory ────────────────────────────────────────────────────────────

    private static InventoryState GetInventory()
    {
        try
        {
            var character = CharacterManager.Instance?.GetFirstLocalCharacter();
            if (character == null) return new InventoryState();

            var inv = character.Inventory;
            if (inv == null) return new InventoryState();

            var pouchItems = new List<InventoryItemEntry>();

            // Pouch (owned items container)
            var pouch = inv.Pouch;
            if (pouch != null)
            {
                var items = pouch.GetContainedItems();
                if (items != null)
                {
                    foreach (var item in items)
                    {
                        if (item == null) continue;
                        bool isFood = item.GetComponent<Food>() != null;
                        bool isEquip = item is Equipment;
                        int qty = 1;
                        if (item is ItemContainer container)
                            qty = container.ItemCount;

                        pouchItems.Add(new InventoryItemEntry
                        {
                            Name     = item.DisplayName ?? item.name,
                            ItemId   = item.ItemID,
                            Quantity = qty,
                            IsFood   = isFood,
                            IsEquipment = isEquip,
                        });
                    }
                }
            }

            // Equipped items via CharacterEquipment
            var equipped = new EquippedItems();
            var equip = inv.Equipment;
            if (equip != null)
            {
                equipped.Weapon   = equip.GetEquippedItem(EquipmentSlot.EquipmentSlotIDs.RightHand)?.DisplayName ?? "";
                equipped.OffHand  = equip.GetEquippedItem(EquipmentSlot.EquipmentSlotIDs.LeftHand)?.DisplayName ?? "";
                equipped.Armor    = equip.GetEquippedItem(EquipmentSlot.EquipmentSlotIDs.Chest)?.DisplayName ?? "";
                equipped.Helmet   = equip.GetEquippedItem(EquipmentSlot.EquipmentSlotIDs.Helmet)?.DisplayName ?? "";
                equipped.Boots    = equip.GetEquippedItem(EquipmentSlot.EquipmentSlotIDs.Foot)?.DisplayName ?? "";
            }

            return new InventoryState { Pouch = pouchItems, Equipped = equipped };
        }
        catch (Exception ex)
        {
            Plugin.Log.LogWarning($"Inventory read error: {ex.Message}");
            return new InventoryState();
        }
    }

    /// <summary>
    /// Unbox an Il2CppSystem.Object returned by reflection to a value type T.
    /// Strategy: try float.Parse on ToString() with InvariantCulture — reliable across types.
    /// </summary>
    private static T Il2CppUnbox<T>(Il2CppSystem.Object obj) where T : struct
    {
        try
        {
            string s = obj.ToString() ?? "0";
            if (typeof(T) == typeof(float))
                return (T)(object)float.Parse(s, System.Globalization.CultureInfo.InvariantCulture);
            return (T)System.Convert.ChangeType(s, typeof(T), System.Globalization.CultureInfo.InvariantCulture);
        }
        catch
        {
            return default;
        }
    }

    // ── Screen message ───────────────────────────────────────────────────────

    private static string GetScreenMessage()
    {
        // TODO: DisplayMessageManager is not present in the IL2CPP interop assemblies.
        // Screen message capture is skipped until the correct class name is confirmed
        // in Assembly-CSharp. Candidates: DisplayMessageManager, NotificationPanel,
        // ItemDisplayedManager. Add the correct type to the interop and re-enable here.
        return "";
    }

}

public class GameState
{
    [JsonPropertyName("type")] public string Type { get; init; } = "game_state";
    [JsonPropertyName("scene")] public string SceneName { get; init; } = "";
    [JsonPropertyName("player")] public PlayerState Player { get; init; } = new();
    [JsonPropertyName("nearby_dead")] public List<NearbyDeadEntry> NearbyDead { get; init; } = new();
    [JsonPropertyName("nearby_interactions")] public List<NearbyInteractionEntry> NearbyInteractions { get; init; } = new();
    [JsonPropertyName("inventory")] public InventoryState Inventory { get; init; } = new();
    [JsonPropertyName("screen_message")] public string ScreenMessage { get; init; } = "";
    [JsonPropertyName("timestamp")] public long Timestamp { get; init; }
}

public class NearbyDeadEntry
{
    [JsonPropertyName("uid")]      public string Uid    { get; init; } = "";
    [JsonPropertyName("name")]     public string Name   { get; init; } = "";
    /// <summary>"character" = died at runtime, "prop" = pre-placed/static</summary>
    [JsonPropertyName("source")]   public string Source { get; init; } = "";
    [JsonPropertyName("x")]        public float  X      { get; init; }
    [JsonPropertyName("y")]        public float  Y      { get; init; }
    [JsonPropertyName("z")]        public float  Z      { get; init; }
    [JsonPropertyName("distance")] public float  Distance { get; init; }
}

public class PlayerState
{
    [JsonPropertyName("health")]           public float Health          { get; init; }
    [JsonPropertyName("max_health")]       public float MaxHealth       { get; init; }
    [JsonPropertyName("stamina")]          public float Stamina         { get; init; }
    [JsonPropertyName("max_stamina")]      public float MaxStamina      { get; init; }
    [JsonPropertyName("mana")]             public float Mana            { get; init; }
    [JsonPropertyName("max_mana")]         public float MaxMana         { get; init; }
    [JsonPropertyName("food")]             public float Food            { get; init; }
    [JsonPropertyName("max_food")]         public float MaxFood         { get; init; }
    [JsonPropertyName("drink")]            public float Drink           { get; init; }
    [JsonPropertyName("max_drink")]        public float MaxDrink        { get; init; }
    [JsonPropertyName("sleep")]            public float Sleep           { get; init; }
    [JsonPropertyName("max_sleep")]        public float MaxSleep        { get; init; }
    [JsonPropertyName("body_temperature")] public float BodyTemperature { get; init; }
    [JsonPropertyName("status_effects")]   public List<string> StatusEffects { get; init; } = new();
    [JsonPropertyName("pos_x")]            public float PositionX       { get; init; }
    [JsonPropertyName("pos_y")]            public float PositionY       { get; init; }
    [JsonPropertyName("pos_z")]            public float PositionZ       { get; init; }
    [JsonPropertyName("rotation_y")]       public float RotationY       { get; init; }
    [JsonPropertyName("camera_rotation_y")]public float CameraRotationY { get; init; }
    [JsonPropertyName("is_dead")]          public bool  IsDead          { get; init; }
    [JsonPropertyName("in_combat")]        public bool  IsInCombat      { get; init; }
}

public class NearbyInteractionEntry
{
    [JsonPropertyName("uid")]      public string Uid      { get; init; } = "";
    [JsonPropertyName("label")]    public string Label    { get; init; } = "";
    [JsonPropertyName("distance")] public float  Distance { get; init; }
    [JsonPropertyName("x")]        public float  X        { get; init; }
    [JsonPropertyName("y")]        public float  Y        { get; init; }
    [JsonPropertyName("z")]        public float  Z        { get; init; }
}

public class InventoryState
{
    [JsonPropertyName("pouch")]    public List<InventoryItemEntry> Pouch    { get; init; } = new();
    [JsonPropertyName("equipped")] public EquippedItems            Equipped { get; init; } = new();
}

public class InventoryItemEntry
{
    [JsonPropertyName("name")]         public string Name        { get; init; } = "";
    [JsonPropertyName("item_id")]      public int    ItemId      { get; init; }
    [JsonPropertyName("quantity")]     public int    Quantity    { get; init; } = 1;
    [JsonPropertyName("is_food")]      public bool   IsFood      { get; init; }
    [JsonPropertyName("is_equipment")] public bool   IsEquipment { get; init; }
}

public class EquippedItems
{
    [JsonPropertyName("weapon")]   public string Weapon  { get; set; } = "";
    [JsonPropertyName("off_hand")] public string OffHand { get; set; } = "";
    [JsonPropertyName("armor")]    public string Armor   { get; set; } = "";
    [JsonPropertyName("helmet")]   public string Helmet  { get; set; } = "";
    [JsonPropertyName("boots")]    public string Boots   { get; set; } = "";
}
